"use strict";(globalThis.webpackChunknumahop_doc_user=globalThis.webpackChunknumahop_doc_user||[]).push([[7477],{91483(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"release-2603","metadata":{"permalink":"/numahop-doc-user/en/blog/release-2603","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2026-04-23-release-2603.md","source":"@site/blog/2026-04-23-release-2603.md","title":"Release NumaHop 26.03","description":"BibLibre a le plaisir d\'annoncer la disponibilit\xe9 de la version NumaHop 26.03, dont Adrien Derobert-Mazure, d\xe9veloppeur, a assur\xe9 le r\xf4le de release manager.","date":"2026-04-23T00:00:00.000Z","tags":[{"inline":false,"label":"Release","permalink":"/numahop-doc-user/en/blog/tags/release"},{"inline":false,"label":"Biblibre","permalink":"/numahop-doc-user/en/blog/tags/biblibre"}],"readingTime":1.35,"hasTruncateMarker":true,"authors":[{"name":"S\xe9verine Queune","title":"BibLibre","page":{"permalink":"/numahop-doc-user/en/blog/authors/squeune"},"imageURL":"/numahop-doc-user/en/img/photos/biblibre.jpg","key":"squeune"},{"name":"Adrien Derobert-Mazure","title":"Biblibre","page":{"permalink":"/numahop-doc-user/en/blog/authors/aderobert"},"imageURL":"/numahop-doc-user/en/img/photos/biblibre.jpg","key":"aderobert"}],"frontMatter":{"slug":"release-2603","title":"Release NumaHop 26.03","tags":["release","biblibre"],"authors":["squeune","aderobert"]},"unlisted":false,"nextItem":{"title":"Journ\xe9es professionnelles 2026","permalink":"/numahop-doc-user/en/blog/journees-2026"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nBibLibre a le plaisir d\'annoncer la disponibilit\xe9 de la version **NumaHop 26.03**, dont Adrien Derobert-Mazure, d\xe9veloppeur, a assur\xe9 le r\xf4le de _release manager_.\\n\\nCette version marque une \xe9tape importante dans l\u2019\xe9volution du logiciel. Elle n\u2019introduit pas de changements majeurs visibles c\xf4t\xe9 interface utilisateur, mais pose des bases essentielles pour les d\xe9veloppements \xe0 venir.\\n\\n<Icon icon={[\\"fa\\", \\"code-pull-request\\"]} /> [La version 26.03 sur GitHub](https://github.com/NumaHOP/NumaHOP/releases/tag/v26.03)\\n\\n\x3c!-- truncate --\x3e\\n\\nD\xe9sormais, NumaHOP adopte un versionnage calendaire, avec deux versions publi\xe9es chaque ann\xe9e, en mars et en septembre. Ce changement vise \xe0 rendre le projet plus lisible et plus pr\xe9visible pour l\u2019ensemble de la communaut\xe9.\\n\\n<Icon icon={[\\"fa\\", \\"github\\"]} /> [Le d\xe9p\xf4t GitHub communautaire](https://github.com/NumaHOP)\\n\\nLa **documentation** \xe9volue, et sera d\xe9sormais centralis\xe9e et g\xe9r\xe9e sur **GitHub**.\\nCette nouvelle organisation vise \xe0 faciliter les contributions et s\u2019inscrit dans une dynamique collaborative. Elle est actuellement disponible en anglais, dans une logique d\u2019internationalisation, et proposera prochainement une solution de traduction. Elle continuera \xe9galement \xe0 s\u2019enrichir progressivement pour couvrir les attentes des diff\xe9rents publics (d\xe9veloppeurs, utilisateurs, administrateurs).\\n\\n<Icon icon={[\\"fa\\", \\"readme\\"]} /> [La documentation developpeur en ligne](https://numahop.github.io/Documentation/)\\n\\nPlusieurs am\xe9liorations ont \xe9t\xe9 apport\xe9es \xe0 la cha\xeene de d\xe9veloppement et \xe0 l\u2019infrastructure, afin de simplifier les processus, renforcer la maintenabilit\xe9 et faciliter les contributions futures. Cette version inclut \xe9galement des corrections de bugs et quelques ajustements fonctionnels.\\n\\nIl s\u2019agit donc d\u2019une **version de transition**, centr\xe9e sur la consolidation des fondations du projet et la pr\xe9paration des prochaines \xe9volutions.\\n\\n<Icon icon={[\\"fa\\", \\"download\\"]} /> [T\xe9l\xe9charger le d\xe9tail de la release 26.03](/img/visuels/release-2603.pdf)"},{"id":"journees-2026","metadata":{"permalink":"/numahop-doc-user/en/blog/journees-2026","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2026-02-15-journees-2026.md","source":"@site/blog/2026-02-15-journees-2026.md","title":"Journ\xe9es professionnelles 2026","description":"Les journ\xe9es professionnelles NumaHop, qui c\xe9l\xe8breront les 10 ans du logiciel libre, auront lieu sur le Campus Condorcet le 19 Novembre 2026 !","date":"2026-02-15T00:00:00.000Z","tags":[{"inline":false,"label":"Journ\xe9es professionnelles","permalink":"/numahop-doc-user/en/blog/tags/journeespro"},{"inline":false,"label":"Humath\xe8que Condorcet","permalink":"/numahop-doc-user/en/blog/tags/humatheque"}],"readingTime":0.18,"hasTruncateMarker":false,"authors":[{"name":"Fran\xe7ois Gandolfi","title":"Humath\xe8que Condorcet","page":{"permalink":"/numahop-doc-user/en/blog/authors/fgandolfi"},"imageURL":"/numahop-doc-user/en/img/photos/fgandolfi.jpg","key":"fgandolfi"}],"frontMatter":{"slug":"journees-2026","title":"Journ\xe9es professionnelles 2026","tags":["journeespro","humatheque"],"authors":"fgandolfi"},"unlisted":false,"prevItem":{"title":"Release NumaHop 26.03","permalink":"/numahop-doc-user/en/blog/release-2603"},"nextItem":{"title":"Journ\xe9es professionnelles 2024","permalink":"/numahop-doc-user/en/blog/journees-2024"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nLes journ\xe9es professionnelles NumaHop, qui c\xe9l\xe8breront les 10 ans du logiciel libre, auront lieu sur le Campus Condorcet le 19 Novembre 2026 !\\n\\n<Icon icon={[\\"fa\\", \\"comment\\"]} /> Assistez et participez !"},{"id":"journees-2024","metadata":{"permalink":"/numahop-doc-user/en/blog/journees-2024","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2024-11-22-journees-2024.md","source":"@site/blog/2024-11-22-journees-2024.md","title":"Journ\xe9es professionnelles 2024","description":"Les journ\xe9es NumaHOP 2024 ont \xe9t\xe9 organis\xe9es conjointement avec l\u2019association des usagers franophones d\u2019Omeka, et ont eu lieu du 20 au 22 novembre \xe0 l\u2019ENS de Lyon.","date":"2024-11-22T00:00:00.000Z","tags":[{"inline":false,"label":"Journ\xe9es professionnelles","permalink":"/numahop-doc-user/en/blog/tags/journeespro"},{"inline":false,"label":"ENS de Lyon","permalink":"/numahop-doc-user/en/blog/tags/enslyon"}],"readingTime":0.26,"hasTruncateMarker":true,"authors":[{"name":"Vincent Tardif","title":"Biblioth\xe8que de l\'ENS","page":{"permalink":"/numahop-doc-user/en/blog/authors/vtardif"},"imageURL":"/numahop-doc-user/en/img/photos/vtardif.jpg","key":"vtardif"}],"frontMatter":{"slug":"journees-2024","title":"Journ\xe9es professionnelles 2024","tags":["journeespro","enslyon"],"authors":"vtardif"},"unlisted":false,"prevItem":{"title":"Journ\xe9es professionnelles 2026","permalink":"/numahop-doc-user/en/blog/journees-2026"},"nextItem":{"title":"Ouvroir 2 NumaHop","permalink":"/numahop-doc-user/en/blog/ouvroir2"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nLes journ\xe9es NumaHOP 2024 ont \xe9t\xe9 organis\xe9es conjointement avec l\u2019association des usagers franophones d\u2019Omeka, et ont eu lieu du 20 au 22 novembre \xe0 l\u2019ENS de Lyon.\\n\\n<Icon icon={[\\"fa\\", \\"signs-post\\"]} /> L\'affiche des journ\xe9es communes\\n\\n\x3c!-- truncate --\x3e\\n\\n![Affiche Journ\xe9es 2024](/img/visuels/journees-2024.png)"},{"id":"ouvroir2","metadata":{"permalink":"/numahop-doc-user/en/blog/ouvroir2","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2023-04-01-ouvroir2.md","source":"@site/blog/2023-04-01-ouvroir2.md","title":"Ouvroir 2 NumaHop","description":"L\u2019Ouvroir 2 NumaHOP est un projet financ\xe9 par le GIS Collex-Pers\xe9e. Depuis mai 2022, une cheffe de projet a \xe9t\xe9 recrut\xe9e au sein des \xe9quipes de l\u2019UAR Pers\xe9e pour travailler sur ce projet.","date":"2023-04-01T00:00:00.000Z","tags":[{"inline":false,"label":"CollEx-Pers\xe9e","permalink":"/numahop-doc-user/en/blog/tags/collex"}],"readingTime":0.96,"hasTruncateMarker":true,"authors":[{"name":"Sarah Gauth\xe9","title":"UAR Pers\xe9e","page":{"permalink":"/numahop-doc-user/en/blog/authors/sgauthe"},"imageURL":"/numahop-doc-user/en/img/logos/persee-logo.png","key":"sgauthe"}],"frontMatter":{"slug":"ouvroir2","title":"Ouvroir 2 NumaHop","tags":["collex"],"authors":"sgauthe"},"unlisted":false,"prevItem":{"title":"Journ\xe9es professionnelles 2024","permalink":"/numahop-doc-user/en/blog/journees-2024"},"nextItem":{"title":"Journ\xe9es professionnelles 2022","permalink":"/numahop-doc-user/en/blog/journees-2022"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nL\u2019Ouvroir 2 NumaHOP est un projet financ\xe9 par le GIS Collex-Pers\xe9e. Depuis mai 2022, une cheffe de projet a \xe9t\xe9 recrut\xe9e au sein des \xe9quipes de l\u2019UAR Pers\xe9e pour travailler sur ce projet.\\n\\n<Icon icon={[\\"fa\\", \\"display\\"]} /> [L\'Ouvroir NumaHop 2 : Automatiser, fluidifier, collaborer et HOP !](https://www-test-collex.inist.fr/projet/louvroir-numahop-2/)\\n\\n\x3c!-- truncate --\x3e\\n\\nL\u2019Ouvroir 2 NumaHOP a pour objectif de d\xe9velopper l\u2019utilisation de NumaHOP au sein de la communaut\xe9 en s\u2019appuyant sur les retours des \xe9tablissements utilisateurs. Pour amplifier l\u2019utilisation de NumaHOP, l\u2019Ouvroir vise \xe0 proposer une documentation d\u2019aide \xe0 l\u2019installation et \xe0 la prise en main et \xe0 travailler sur une solution d\u2019h\xe9bergement de la plateforme. Pour ce faire, deux axes de travail ont \xe9t\xe9 d\xe9termin\xe9s :\\n\\n- Faciliter la mise en \u0153uvre de NumaHop gr\xe2ce \xe0 un site web r\xe9unissant l\u2019ensemble des ressources techniques et documentaires n\xe9cessaires \xe0 l\u2019installation et la prise en main du progiciel par les \xe9quipes locales.\\n- Etudier les conditions de l\u2019ouverture d\u2019une instance mutualis\xe9e de NumaHOP tenant compte des conditions techniques, mat\xe9rielles, humaines et \xe9conomiques pour sa r\xe9alisation, ainsi que des sc\xe9narios de gouvernance pour la future plateforme."},{"id":"journees-2022","metadata":{"permalink":"/numahop-doc-user/en/blog/journees-2022","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2022-11-24-journees-2022.md","source":"@site/blog/2022-11-24-journees-2022.md","title":"Journ\xe9es professionnelles 2022","description":"La journ\xe9e profesionnelle NumaHOP 2022 s\u2019est tenue \xe0 l\u2019Universit\xe9 Paris Saclay  le 24 novembre. Au programme : pr\xe9sentations, \xe9changes, et ateliers pour comprendre le fonctionnement de la communaut\xe9 utilisateurs.","date":"2022-11-24T00:00:00.000Z","tags":[{"inline":false,"label":"Journ\xe9es professionnelles","permalink":"/numahop-doc-user/en/blog/tags/journeespro"},{"inline":false,"label":"Universit\xe9 Paris Saclay","permalink":"/numahop-doc-user/en/blog/tags/saclay"}],"readingTime":1.7,"hasTruncateMarker":true,"authors":[{"name":"Oriane Boissel","title":"Universit\xe9 Paris Saclay","page":{"permalink":"/numahop-doc-user/en/blog/authors/oboissel"},"imageURL":"/numahop-doc-user/en/img/photos/oboissel.jpg","key":"oboissel"}],"frontMatter":{"slug":"journees-2022","title":"Journ\xe9es professionnelles 2022","tags":["journeespro","saclay"],"authors":"oboissel"},"unlisted":false,"prevItem":{"title":"Ouvroir 2 NumaHop","permalink":"/numahop-doc-user/en/blog/ouvroir2"},"nextItem":{"title":"Un premier article pour NumaHop !","permalink":"/numahop-doc-user/en/blog/article-2020"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nLa journ\xe9e profesionnelle NumaHOP 2022 s\u2019est tenue \xe0 l\u2019Universit\xe9 Paris Saclay  le 24 novembre. Au programme : pr\xe9sentations, \xe9changes, et ateliers pour comprendre le fonctionnement de la communaut\xe9 utilisateurs.\\n\\n<Icon icon={[\\"fa\\", \\"circle-play\\"]} /> Retrouvez toutes les interventions en vid\xe9o !\\n\\n<Icon icon={[\\"fa\\", \\"signs-post\\"]} /> Le programme de la journ\xe9e\\n\\n\x3c!-- truncate --\x3e\\n\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [\\"NumaHOP en 2022\\"](https://www.youtube.com/watch?v=2MfVb5qzHew&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2), allocution d\u2019Herv\xe9 Dole, vice pr\xe9sident charg\xe9 de la culture \xe0 l\u2019Universit\xe9 Paris Saclay.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Retour d\u2019exp\xe9riences : les nouveaux utilisateurs de NumaHOP](https://www.youtube.com/watch?v=m5lVzfwx9CI&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=2), par Christophe Coignard (ENS de Paris), Laurence Gandois, Oriane Boissel (Universit\xe9 Paris Saclay) et Solenne Coutagne (Mus\xe9um national d\u2019Histoire Naturelle). Echange anim\xe9 par Sarah Gauth\xe9 (Pers\xe9e).\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [NumaHOP et ses usages : tour d\u2019horizon et d\xe9tournements](https://www.youtube.com/watch?v=64OCk8ckFwU&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=3), par Fran\xe7ois-Xavier Boffy (Universit\xe9 Lyon 1), Sylvie Sall\xe9 et Oriane Boissel (Universit\xe9 Paris Saclay), Pierre-Marie Bartoli (INHA). Echange anim\xe9 par Palmira de Sousa (Campus Condorcet).\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> Pr\xe9sentations flash: \\n  - [Le connecteur Limb Gallery](https://www.youtube.com/watch?v=0tLllZGQx3s&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=4), par Adeline Batailler (Sorbonne Universit\xe9).\\n  - [Le connecteur Omeka](https://www.youtube.com/watch?v=N__NvJb5OT0&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=6), par Pauline Rivi\xe8re (Biblioth\xe8que Sainte Genevi\xe8ve) et Olesea Dubois (Biblioth\xe8que de Sciences Po Paris)\\n  - [PDF oc\xe9ris\xe9s versus non oc\xe9ris\xe9s](https://www.youtube.com/watch?v=IDaoqkvYk4o&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=5), par Adeline Batailler (Sorbonne Universit\xe9).\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Pr\xe9sentation g\xe9n\xe9rale de NumaHOP](https://www.youtube.com/watch?v=JRLUKbGO7RE&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=7), par Laurence Gandois (Universit\xe9 Paris Saclay) et Pauline Rivi\xe8re (Biblioth\xe8que Sainte Genevi\xe8ve).\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [NumaHOP et les archives](https://www.youtube.com/watch?v=1K0FoVjaHh0&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=8), par Victor Beillard (Sorbonne Universit\xe9), Olesea Dubois (Biblioth\xe8que Sciences Po Paris), Nathalie Pilet (BULAC).\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Projet Collex Ouvroir 2 NumaHOP : un point d\u2019\xe9tape](https://www.youtube.com/watch?v=bbteyljxWSA&list=PLJFDLbH_mXeccEFt6RUI8PdUzV4NXGuP2&index=9), par Sarah Gauth\xe9 (Pers\xe9e).\\n\\n![Affiche Journ\xe9es 2024](/img/visuels/journees-2022.png)"},{"id":"article-2020","metadata":{"permalink":"/numahop-doc-user/en/blog/article-2020","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2020-10-11-article-2020.md","source":"@site/blog/2020-10-11-article-2020.md","title":"Un premier article pour NumaHop !","description":"Olesea Dubois, Fanny Mion-Mouton et Pauline Rivi\xe8re, \\"NumaHOP, une plateforme de gestion de contenus num\xe9ris\xe9s\\", Arabesques, 99, 2020.","date":"2020-10-11T00:00:00.000Z","tags":[{"inline":false,"label":"Publication","permalink":"/numahop-doc-user/en/blog/tags/article"},{"inline":false,"label":"Biblioth\xe8que Sainte Genevi\xe8ve","permalink":"/numahop-doc-user/en/blog/tags/bsg"},{"inline":false,"label":"Sciences Po Paris","permalink":"/numahop-doc-user/en/blog/tags/sciencespo"}],"readingTime":0.2,"hasTruncateMarker":false,"authors":[{"name":"Olesea Dubois","title":"Sciences Po Paris","page":{"permalink":"/numahop-doc-user/en/blog/authors/odubois"},"imageURL":"/numahop-doc-user/en/img/photos/odubois.jpg","key":"odubois"},{"name":"Pauline Rivi\xe8re","title":"Biblioth\xe8que Sainte Genevi\xe8ve","page":{"permalink":"/numahop-doc-user/en/blog/authors/priviere"},"imageURL":"/numahop-doc-user/en/img/photos/priviere.jpg","key":"priviere"}],"frontMatter":{"slug":"article-2020","title":"Un premier article pour NumaHop !","tags":["article","bsg","sciencespo"],"authors":["odubois","priviere"]},"unlisted":false,"prevItem":{"title":"Journ\xe9es professionnelles 2022","permalink":"/numahop-doc-user/en/blog/journees-2022"},"nextItem":{"title":"Journ\xe9es professionnelles 2019","permalink":"/numahop-doc-user/en/blog/journees-2019"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nOlesea Dubois, Fanny Mion-Mouton et Pauline Rivi\xe8re, \\"NumaHOP, une plateforme de gestion de contenus num\xe9ris\xe9s\\", Arabesques, 99, 2020.\\n\\n<Icon icon={[\\"fa\\", \\"external-link\\"]} />  Retrouvez l\'article sur [Arabesques](https://dx.doi.org/10.35562/arabesques.2239) !"},{"id":"journees-2019","metadata":{"permalink":"/numahop-doc-user/en/blog/journees-2019","editUrl":"https://gitlab.com/fgandolfi/numahop-doc-user/-/edit/main/blog/2019-10-08-journees-2019.md","source":"@site/blog/2019-10-08-journees-2019.md","title":"Journ\xe9es professionnelles 2019","description":"La premi\xe8re journ\xe9e profesionnelle NumaHOP s\u2019est tenue \xe0 la BULAC (Paris) dans l\u2019auditorium du P\xf4le Langues et Civilisation le 18 octobre 2019. Y \xe9taient programm\xe9es des pr\xe9sentations, des \xe9changes, des ateliers pour pr\xe9senter le progiciel.","date":"2019-10-08T00:00:00.000Z","tags":[{"inline":false,"label":"Journ\xe9es professionnelles","permalink":"/numahop-doc-user/en/blog/tags/journeespro"},{"inline":false,"label":"Universit\xe9 Paris Saclay","permalink":"/numahop-doc-user/en/blog/tags/saclay"}],"readingTime":2.01,"hasTruncateMarker":true,"authors":[{"name":"Nathalie Pilet","title":"Biblioth\xe8que universitaire des langues et civilisations","page":{"permalink":"/numahop-doc-user/en/blog/authors/npilet"},"imageURL":"/numahop-doc-user/en/img/photos/npilet.jpg","key":"npilet"}],"frontMatter":{"slug":"journees-2019","title":"Journ\xe9es professionnelles 2019","tags":["journeespro","saclay"],"authors":"npilet"},"unlisted":false,"prevItem":{"title":"Un premier article pour NumaHop !","permalink":"/numahop-doc-user/en/blog/article-2020"}},"content":"import Icon from \'@site/src/components/Icon\';\\n\\nLa premi\xe8re journ\xe9e profesionnelle NumaHOP s\u2019est tenue \xe0 la BULAC (Paris) dans l\u2019auditorium du P\xf4le Langues et Civilisation le 18 octobre 2019. Y \xe9taient programm\xe9es des pr\xe9sentations, des \xe9changes, des ateliers pour pr\xe9senter le progiciel.\\n\\n<Icon icon={[\\"fa\\", \\"circle-play\\"]} />  Retrouvez toutes les interventions en vid\xe9o !\\n\\n\x3c!-- truncate --\x3e\\n\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Pourquoi une journ\xe9e NumaHOP ?](https://www.youtube.com/watch?v=9iVJMFaQ7MA&t=9s) Allocution de Fran\xe7ois Cavalier, directeur de la biblioth\xe8ques de Sciences Po Paris et Marie-Lise Tsagouria, directeur de la BULAC.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Qu\u2019est-ce qu\u2019un logiciel libre ?](https://www.youtube.com/watch?v=V-5Ux7l9rJk&t=1s) avec C\xe9cile Gobbo, responsable du p\xf4le Flux et Donn\xe9es \xe0 la BULAC et Nocpmas Legrand, administrateur technique du syst\xe8me d\u2019information documentaire \xe0 la BULAC.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Retour d\u2019exp\xe9riences](https://www.youtube.com/watch?v=DbvXiuVewg0&t=3s), par C\xe9cilia Piccioli, charg\xe9e des traitements de conservation \xe0 la BULAC, Pauline Bougon, charg\xe9e de num\xe9risation \xe0 la direction des ressources et de l\u2019information scientifique \xe0 Sciences Po Paris, Pauline Rivi\xe8re, chef de projet num\xe9risation \xe0 la biblioth\xe8que Sainte-Genevi\xe8ve. S\xe9ance anim\xe9e par Fanny Mion-Mouton, responsable adjointe du p\xf4le Flux et Donn\xe9es \xe0 la BULAC et responsable de l\u2019\xe9quipe signalement et exposition des donn\xe9es \xe0 la BULAC.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Regards des op\xe9rateurs nationaux](https://www.youtube.com/watch?v=t_IByhWNyS4), par Thomas Ledoux, charg\xe9 de la coordination projets DSI \xe0 la Biblioth\xe8que nationale de France, Alexia de Casanove, d\xe9partement Archivage et Diffusion du CINES, Alain Colas, directeur du GIS Collex-Pers\xe9e, Viviane Boul\xe9treau, responsable du p\xf4le informatique de Pers\xe9e. Echange anim\xe9 par Fran\xe7ois Cavalier, directeur de la biblioth\xe8que de Sciences Po Paris.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Installer NumaHOP : quelles options pour mon \xe9tablissement ?](https://www.youtube.com/watch?v=bc5OQxKiEwg) Lo\xefc Charlery, responsable des infrastructures de la biblioth\xe8que Sainte-Genevi\xe8ve, Olivier Pouchard, responsable du service \xe9tudes et d\xe9veloppements \xe0 Sciences Po Paris, Christophe Paris, chef de l\u2019\xe9quipe informatique \xe0 la BULAC. Echange anim\xe9 par St\xe9phane Auzanneau, directeur de la DSI \xe0 Sciences Po Paris.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Progilone : quelles possibilit\xe9s d\u2019h\xe9bergement ?] pr\xe9sent\xe9 par Anne Dupiat, chef de projet Progilone.\\n- <Icon icon={[\\"fa\\", \\"video\\"]} /> [Et la suite : comment structurer une communaut\xe9 NumaHOP ?](https://www.youtube.com/watch?v=HTCkc5uaOFc), par Fran\xe7ois Cavalier, directeur de la biblioth\xe8que de Sciences Po Paris, Marie-Lise Tsagouria, directeur de la BULAC et Claire Sonnefraud, responsable du d\xe9partement de la conservation \xe0 la biblioth\xe8que Sainte-Genevi\xe8ve."}]}}')}}]);